import{_ as r,o as a,c as d,a2 as o}from"./chunks/framework.Cd7uensT.js";const c=JSON.parse('{"title":"资产管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/device-management.md","filePath":"guide/features/device-management.md","lastUpdated":1781673626000}'),e={name:"guide/features/device-management.md"};function l(i,t,n,s,h,g){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="资产管理" tabindex="-1">资产管理 <a class="header-anchor" href="#资产管理" aria-label="Permalink to &quot;资产管理&quot;">​</a></h1><h2 id="设备管理" tabindex="-1">设备管理 <a class="header-anchor" href="#设备管理" aria-label="Permalink to &quot;设备管理&quot;">​</a></h2><p>设备管理是系统的核心功能，提供设备全生命周期管理。</p><h3 id="设备状态流转" tabindex="-1">设备状态流转 <a class="header-anchor" href="#设备状态流转" aria-label="Permalink to &quot;设备状态流转&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>采购中 → 待安装 → 运行中 ⇄ 维护中 → 已报废</span></span></code></pre></div><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><strong>采购中</strong></td><td>设备已采购，尚未到货</td></tr><tr><td><strong>待安装</strong></td><td>设备到货，等待安装</td></tr><tr><td><strong>运行中</strong></td><td>设备正常运行</td></tr><tr><td><strong>维护中</strong></td><td>设备正在维护</td></tr><tr><td><strong>已报废</strong></td><td>设备已报废处理</td></tr></tbody></table><h3 id="新增设备" tabindex="-1">新增设备 <a class="header-anchor" href="#新增设备" aria-label="Permalink to &quot;新增设备&quot;">​</a></h3><ol><li>进入「设备管理」页面</li><li>点击「新增设备」按钮</li><li>填写设备信息：名称、类型、型号、序列号、品牌、所属机房、机柜、U位、状态等</li><li>点击「确定」保存</li></ol><h3 id="批量导入" tabindex="-1">批量导入 <a class="header-anchor" href="#批量导入" aria-label="Permalink to &quot;批量导入&quot;">​</a></h3><ol><li>点击「导入」按钮</li><li>下载导入模板（Excel/CSV格式）</li><li>按模板格式填写设备信息</li><li>上传文件，系统自动解析并导入</li></ol><h3 id="设备导出" tabindex="-1">设备导出 <a class="header-anchor" href="#设备导出" aria-label="Permalink to &quot;设备导出&quot;">​</a></h3><ol><li>选择需要导出的设备（可多选）</li><li>点击「导出」按钮</li><li>选择导出格式（Excel/CSV）</li><li>文件自动下载</li></ol><h3 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h3><p>系统支持对多台设备进行批量管理，提升运维效率：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>批量修改</strong></td><td>选中多台设备，批量修改机房、机柜、状态、负责人等公共属性</td></tr><tr><td><strong>批量删除</strong></td><td>选中多台设备，批量删除不再管理的设备记录</td></tr><tr><td><strong>批量导出</strong></td><td>按筛选条件或手动选择范围，导出为 Excel 或 CSV 格式</td></tr><tr><td><strong>批量移动</strong></td><td>将选中的设备批量迁移至指定机柜或机房</td></tr></tbody></table><p>操作方式：在设备列表勾选目标设备，点击列表上方的批量操作按钮，在弹出的对话框中填写修改内容后确认提交。</p><h2 id="端口管理" tabindex="-1">端口管理 <a class="header-anchor" href="#端口管理" aria-label="Permalink to &quot;端口管理&quot;">​</a></h2><p>端口管理用于配置设备的网络端口信息，是网络运维的基础数据支撑。</p><blockquote><p><strong>v2.1.1 更新</strong>：端口管理页面已改为<strong>按设备分组分页</strong>展示，解决了端口数量过多时部分设备不显示的问题。端口名称统一使用自然排序，展示顺序更直观。</p></blockquote><h3 id="端口类型" tabindex="-1">端口类型 <a class="header-anchor" href="#端口类型" aria-label="Permalink to &quot;端口类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>网口</strong></td><td>以太网接口（RJ45），通常为 10/100/1000Mbps 自适应电口</td></tr><tr><td><strong>光口</strong></td><td>光纤接口（SFP/SFP+/QSFP），支持千兆/万兆/25G/40G/100G 传输速率</td></tr><tr><td><strong>管理口</strong></td><td>带外管理接口（如 iLO、iDRAC、BMC），用于远程管理设备</td></tr><tr><td><strong>其他</strong></td><td>其他类型接口（如 Console 口、USB 口、串口等）</td></tr></tbody></table><h3 id="端口属性" tabindex="-1">端口属性 <a class="header-anchor" href="#端口属性" aria-label="Permalink to &quot;端口属性&quot;">​</a></h3><p>每个端口包含以下信息：</p><table tabindex="0"><thead><tr><th>属性</th><th>说明</th></tr></thead><tbody><tr><td><strong>端口名称</strong></td><td>如 eth0、GigabitEthernet0/0/1 等</td></tr><tr><td><strong>端口类型</strong></td><td>网口/光口/管理口/其他</td></tr><tr><td><strong>MAC地址</strong></td><td>端口的物理地址</td></tr><tr><td><strong>速率</strong></td><td>端口协商速率（如 1000Mbps、10Gbps）</td></tr><tr><td><strong>绑定网卡</strong></td><td>将该端口关联到已纳管的网卡设备</td></tr><tr><td><strong>连接状态</strong></td><td>已连接/未连接</td></tr><tr><td><strong>连接对象</strong></td><td>该端口所连接的交换机端口或对端设备端口</td></tr><tr><td><strong>备注</strong></td><td>端口用途描述等补充信息</td></tr></tbody></table><h3 id="绑定网卡" tabindex="-1">绑定网卡 <a class="header-anchor" href="#绑定网卡" aria-label="Permalink to &quot;绑定网卡&quot;">​</a></h3><p>端口管理支持将端口与已记录的网卡设备进行绑定。操作路径：设备详情页 → 端口管理 → 点击指定端口的「绑定网卡」按钮 → 搜索并选择目标网卡 → 确认绑定。绑定后可在网卡详情页查看关联的物理端口信息。</p><h3 id="批量管理端口" tabindex="-1">批量管理端口 <a class="header-anchor" href="#批量管理端口" aria-label="Permalink to &quot;批量管理端口&quot;">​</a></h3><ol><li>在设备详情页进入「端口管理」标签页</li><li>勾选多个端口</li><li>点击「批量编辑」按钮</li><li>可批量修改端口类型、速率、备注等属性</li><li>确认后一次性保存所有修改</li></ol><h2 id="接线管理" tabindex="-1">接线管理 <a class="header-anchor" href="#接线管理" aria-label="Permalink to &quot;接线管理&quot;">​</a></h2><p>接线管理用于记录机柜间、设备间的线缆连接关系，支持线缆可视化追踪和清单导出。</p><h3 id="连接关系" tabindex="-1">连接关系 <a class="header-anchor" href="#连接关系" aria-label="Permalink to &quot;连接关系&quot;">​</a></h3><p>接线管理记录完整的连接拓扑信息：</p><table tabindex="0"><thead><tr><th>信息项</th><th>说明</th></tr></thead><tbody><tr><td><strong>源设备</strong></td><td>线缆起始端设备</td></tr><tr><td><strong>源端口</strong></td><td>起始端设备的具体端口</td></tr><tr><td><strong>目标设备</strong></td><td>线缆终止端设备</td></tr><tr><td><strong>目标端口</strong></td><td>终止端设备的具体端口</td></tr><tr><td><strong>线缆类型</strong></td><td>网线、光纤、电源线、串口线等</td></tr><tr><td><strong>线缆编号</strong></td><td>物理线缆的唯一标识</td></tr><tr><td><strong>长度（米）</strong></td><td>线缆物理长度</td></tr><tr><td><strong>备注</strong></td><td>走线路由、标签等补充信息</td></tr></tbody></table><h3 id="创建接线" tabindex="-1">创建接线 <a class="header-anchor" href="#创建接线" aria-label="Permalink to &quot;创建接线&quot;">​</a></h3><ol><li>进入设备详情页 → 「接线管理」标签页</li><li>点击「新增接线」按钮</li><li>选择源设备与源端口</li><li>选择目标设备与目标端口</li><li>填写线缆编号、类型、长度等信息</li><li>点击「确定」保存</li></ol><h3 id="可视化追踪" tabindex="-1">可视化追踪 <a class="header-anchor" href="#可视化追踪" aria-label="Permalink to &quot;可视化追踪&quot;">​</a></h3><p>接线管理支持对特定设备或端口进行连接追踪：</p><ul><li><strong>正向追踪</strong>：从指定端口出发，查看其链接到哪些目标设备端口</li><li><strong>反向追踪</strong>：查看哪些设备的端口链接到当前端口</li><li><strong>全链路追踪</strong>：从源设备出发，沿连接关系逐跳展示完整链路路径</li></ul><p>追踪结果以拓扑图形式展示，支持高亮显示追踪路径。</p><h3 id="清单导出" tabindex="-1">清单导出 <a class="header-anchor" href="#清单导出" aria-label="Permalink to &quot;清单导出&quot;">​</a></h3><ol><li>在接线管理页面设置筛选条件（按机房、机柜、设备、线缆类型等）</li><li>点击「导出接线清单」按钮</li><li>选择导出格式（Excel/CSV）</li><li>导出的清单包含：源设备、源端口、目标设备、目标端口、线缆编号、线缆类型、长度等信息</li></ol><h2 id="网络拓扑" tabindex="-1">网络拓扑 <a class="header-anchor" href="#网络拓扑" aria-label="Permalink to &quot;网络拓扑&quot;">​</a></h2><p>网络拓扑以可视化方式展示数据中心内设备的网络连接关系，基于 ReactFlow 引擎实现。</p><h3 id="拓扑展示" tabindex="-1">拓扑展示 <a class="header-anchor" href="#拓扑展示" aria-label="Permalink to &quot;拓扑展示&quot;">​</a></h3><ul><li><strong>自动布局</strong>：根据设备间的连接关系自动生成拓扑图布局</li><li><strong>节点展示</strong>：每个设备为一个节点，显示设备名称、类型、IP 地址等关键信息</li><li><strong>连线展示</strong>：设备间的连接关系以连线表示，不同线缆类型使用不同颜色和线型区分</li><li><strong>状态标识</strong>：设备节点根据运行状态显示对应颜色标识，异常设备高亮警示</li></ul><h3 id="交互操作" tabindex="-1">交互操作 <a class="header-anchor" href="#交互操作" aria-label="Permalink to &quot;交互操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td><strong>拖拽画布</strong></td><td>鼠标左键拖拽空白区域平移视图</td></tr><tr><td><strong>缩放画布</strong></td><td>鼠标滚轮缩放</td></tr><tr><td><strong>查看设备详情</strong></td><td>点击设备节点弹出详情面板</td></tr><tr><td><strong>查看连接详情</strong></td><td>点击连接线查看连接信息</td></tr><tr><td><strong>框选节点</strong></td><td>按住 Shift 拖拽鼠标框选多个设备</td></tr><tr><td><strong>导出拓扑图</strong></td><td>点击导出按钮保存为图片</td></tr></tbody></table><h3 id="拓扑过滤" tabindex="-1">拓扑过滤 <a class="header-anchor" href="#拓扑过滤" aria-label="Permalink to &quot;拓扑过滤&quot;">​</a></h3><p>支持按以下条件过滤拓扑展示内容：</p><ul><li>按机房/机柜范围过滤</li><li>按设备类型过滤（服务器、交换机、存储等）</li><li>按设备状态过滤</li><li>按连接类型过滤</li></ul><h2 id="字段管理" tabindex="-1">字段管理 <a class="header-anchor" href="#字段管理" aria-label="Permalink to &quot;字段管理&quot;">​</a></h2><p>字段管理用于自定义设备属性，满足不同场景下的资产管理需求。</p><h3 id="支持字段类型" tabindex="-1">支持字段类型 <a class="header-anchor" href="#支持字段类型" aria-label="Permalink to &quot;支持字段类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>文本</strong></td><td>单行文本输入</td></tr><tr><td><strong>数字</strong></td><td>数值输入</td></tr><tr><td><strong>日期</strong></td><td>日期选择器</td></tr><tr><td><strong>日期时间</strong></td><td>日期+时间选择器</td></tr><tr><td><strong>下拉选择</strong></td><td>单选下拉框，可自定义选项列表</td></tr><tr><td><strong>多选</strong></td><td>多选下拉框，可同时选择多个选项</td></tr><tr><td><strong>多行文本</strong></td><td>长文本输入</td></tr><tr><td><strong>开关</strong></td><td>布尔值开关</td></tr><tr><td><strong>人员选择</strong></td><td>从系统用户中选择</td></tr></tbody></table><h3 id="管理自定义字段" tabindex="-1">管理自定义字段 <a class="header-anchor" href="#管理自定义字段" aria-label="Permalink to &quot;管理自定义字段&quot;">​</a></h3><ol><li>进入「设备管理」页面 → 「字段管理」标签页</li><li>点击「新增字段」按钮</li><li>填写字段信息：字段名称、字段类型、是否必填、排序、默认值、选项列表（下拉/多选类型需要）</li><li>保存后，自定义字段将自动出现在设备新增/编辑表单中</li></ol><h3 id="字段排序与可见性" tabindex="-1">字段排序与可见性 <a class="header-anchor" href="#字段排序与可见性" aria-label="Permalink to &quot;字段排序与可见性&quot;">​</a></h3><ul><li><strong>排序</strong>：拖拽调整自定义字段在表单中的排列顺序</li><li><strong>可见性</strong>：可设置字段在列表和表单中的显示/隐藏</li><li><strong>必填校验</strong>：设置为必填的字段在保存时会进行非空校验</li></ul>',58)])])}const u=r(e,[["render",l]]);export{c as __pageData,u as default};
